import numpy as np

def mode_spacing(N_ions, omega_z_MHz):
    # Approximate: spacing ~ omega_z / N for large N
    return omega_z_MHz / N_ions

print("Mode spacing vs number of ions (omega_z = 1 MHz):\n")
for N in [2, 5, 10, 20, 50, 100]:
    spacing = mode_spacing(N, 1.0)
    print(f"N = {N:3d}: spacing ~ {spacing*1000:.0f} kHz")
    if spacing * 1000 < 10:
        print(f"         WARNING: May be difficult to resolve modes!")
